// CLX City Scan Discovery — Phase 11: Build Scan List
// Creates all 35 city + industry combinations for Google Maps scanning

const cities = ['Toronto', 'Vancouver', 'Calgary', 'Ottawa', 'Mississauga'];

const industries = [
  { query: 'insurance broker', product_type: 'insurance' },
  { query: 'construction company', product_type: 'construction' },
  { query: 'cleaning services', product_type: 'cleaning' },
  { query: 'moving company', product_type: 'moving' },
  { query: 'marketing agency', product_type: 'marketing' },
  { query: 'consulting firm', product_type: 'consulting' },
  { query: 'real estate agency', product_type: 'real_estate' }
];

const scanList = [];

for (const city of cities) {
  for (const ind of industries) {
    scanList.push({
      city: city,
      industry: ind.query,
      product_type: ind.product_type,
      search_query: ind.query + ' in ' + city + ' Canada'
    });
  }
}

return scanList.map(item => ({ json: item }));

// CLX City Scan Discovery — Phase 11: Parse Search Results
// Extracts business details from Google Custom Search API response
// Response contains items[] with title, link, snippet, formattedUrl

try {
  const response = $('Search Google').item.json;
  const scanContext = $('Split In Batches').item.json;

  console.log('[CLX City Scan] Parsing results for: ' + scanContext.industry + ' in ' + scanContext.city);
  console.log('[CLX City Scan] Response keys: ' + Object.keys(response).join(', '));

  const items = response.items || [];

  console.log('[CLX City Scan] Results count: ' + items.length);

  if (items.length === 0) {
    console.log('[CLX City Scan] No results found for: ' + scanContext.industry + ' in ' + scanContext.city);
    return { json: { businesses: [], count: 0, city: scanContext.city, industry: scanContext.industry } };
  }

  const businesses = [];
  const seen = {};

  for (const item of items) {
    // Extract business name from title — strip trailing location/suffix after dash or pipe
    let name = (item.title || '').split(' - ')[0].split(' | ')[0].trim();
    if (!name) continue;

    // Deduplicate by name within same search
    if (seen[name.toLowerCase()]) continue;
    seen[name.toLowerCase()] = true;

    businesses.push({
      name: name,
      website: item.link || '',
      formatted_address: item.snippet || '',
      formatted_phone_number: '',
      place_id: '',
      city: scanContext.city,
      industry: scanContext.industry,
      product_type: scanContext.product_type,
      search_query: scanContext.search_query
    });
  }

  console.log('[CLX City Scan] Parsed ' + businesses.length + ' businesses for: ' + scanContext.industry + ' in ' + scanContext.city);

  return { json: { businesses: businesses, count: businesses.length, city: scanContext.city, industry: scanContext.industry } };
} catch (error) {
  const scanContext = $('Split In Batches').item.json;
  console.log('[CLX City Scan] ERROR parsing results: ' + error.message);
  return { json: { businesses: [], count: 0, city: scanContext.city, industry: scanContext.industry, parse_error: error.message } };
}

// CLX City Scan Discovery — Phase 11: Process Each Business
// Converts Google Maps businesses into individual Crystallux lead items
// Reads city/industry/product_type from Split In Batches as primary source

const data = $('Parse Places Results').item.json;
const scanContext = $('Split In Batches').item.json;
const businesses = data.businesses || [];

if (businesses.length === 0) {
  return { json: { skip: true } };
}

const now = new Date().toISOString();
const city = scanContext.city;
const industry = scanContext.industry;
const productType = scanContext.product_type;

const leads = businesses.map(biz => ({
  json: {
    full_name: '',
    email: '',
    phone: biz.formatted_phone_number || '',
    company: biz.name,
    job_title: 'Owner',
    industry: industry,
    city: city,
    source: 'google_maps',
    lead_status: 'New Lead',
    product_type: productType,
    do_not_contact: false,
    unsubscribed: false,
    total_emails_sent: 0,
    lead_score: 0,
    assigned_to: '',
    notes: 'Google Maps place_id: ' + (biz.place_id || '') + ' | Address: ' + (biz.formatted_address || '') + (biz.website ? ' | Website: ' + biz.website : ''),
    updated_at: now
  }
}));

return leads;
